triggered := false
if ((#MotionSensor).motionSensor_motion == true) {
if (triggered == false) {
new_bright = (#Light).light_currentBrightness + 10
        if (new_bright >= 100) {
(#Light).light_moveToBrightness(100, 0)
            break
}
else {
(#Light).light_moveToBrightness(new_bright, 0)
}
triggered = true
}
}
else {
triggered = false
}

